style.css:
:root {
  --bg: #0a0a0a;
  --text: #e1e1e1;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background-color: var(--bg);
  color: var(--text);
  font-family: "Space Grotesk", sans-serif;
  overflow-x: hidden;
  min-height: 100vh;
}

/* Noise Texture */
.noise {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 9999;
  opacity: 0.05;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
}

/* Hero Section */
.hero {
  height: 100vh;
  width: 100%;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  position: relative;
  z-index: 1;
}

/* Morph Effect: Blur + Threshold */
.morph-container {
  position: relative;
  font-size: clamp(3rem, 15vw, 10rem);
  font-weight: 700;
  filter: url(#threshold);
  user-select: none;
}

.word-rotator {
  position: relative;
  height: 1.2em;
  width: 100%;
  min-width: 14ch;
  display: flex;
  justify-content: center;
  align-items: center;
}

.word {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  opacity: 0;
  color: var(--text);
  white-space: nowrap;
  animation: rotate-words 9s infinite ease-in-out;
}

.word:nth-child(1) {
  animation-delay: 0s;
}

.word:nth-child(2) {
  animation-delay: 3s;
}

.word:nth-child(3) {
  animation-delay: 6s;
}

@keyframes rotate-words {
  0% {
    opacity: 0;
    filter: blur(20px);
    transform: translate(-50%, -50%) scale(0.8);
  }

  5% {
    opacity: 0.5;
    filter: blur(10px);
  }

  15%,
  35% {
    opacity: 1;
    filter: blur(0px);
    transform: translate(-50%, -50%) scale(1);
  }

  45% {
    opacity: 0.5;
    filter: blur(10px);
  }

  50%,
  100% {
    opacity: 0;
    filter: blur(20px);
    transform: translate(-50%, -50%) scale(1.2);
  }
}

/* Subtext */
.subtext {
  margin-top: 2rem;
  font-size: 1.2rem;
  text-transform: uppercase;
  letter-spacing: 0.2em;
  color: #888;
  opacity: 0;
  animation: fade-up 1s ease-out 1s forwards;
}

@keyframes fade-up {
  from {
    opacity: 0;
    transform: translateY(20px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fade-in {
  to {
    opacity: 1;
  }
}

/* Scroll Indicator */
.scroll-indicator {
  position: absolute;
  bottom: 2rem;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.5rem;
  opacity: 0;
  animation: fade-in 1s ease-out 2s forwards;
}

.mouse {
  width: 24px;
  height: 40px;
  border: 2px solid rgba(255, 255, 255, 0.3);
  border-radius: 20px;
  position: relative;
}

.wheel {
  width: 2px;
  height: 6px;
  background: #fff;
  position: absolute;
  top: 8px;
  left: 50%;
  transform: translateX(-50%);
  border-radius: 2px;
  animation: scroll 1.5s infinite;
}

@keyframes scroll {
  0% {
    transform: translate(-50%, 0);
    opacity: 1;
  }

  100% {
    transform: translate(-50%, 15px);
    opacity: 0;
  }
}

/* Content Section */
.content {
  padding: 8rem 2rem;
  max-width: 1200px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4rem;
  align-items: center;
}

.content-text h2 {
  font-size: 3rem;
  margin-bottom: 2rem;
  line-height: 1.1;
}

.content-text p {
  font-size: 1.1rem;
  color: #aaa;
  line-height: 1.6;
  margin-bottom: 2rem;
}

.card {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.05);
  padding: 2rem;
  border-radius: 1px;
  position: relative;
  overflow: hidden;
}

.card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  /* Subtle hover gradient */
  background: radial-gradient(
    circle at 50% 50%,
    rgba(255, 255, 255, 0.06),
    transparent 60%
  );
  opacity: 0;
  transition: opacity 0.5s;
}

.card:hover::before {
  opacity: 1;
}

.card:hover {
  border-color: rgba(255, 255, 255, 0.2);
}

.filters {
  position: absolute;
  width: 0;
  height: 0;
  pointer-events: none;
}

@media (max-width: 768px) {
  .content {
    grid-template-columns: 1fr;
    padding: 4rem 1.5rem;
  }

  .morph-container {
    font-size: 15vw;
  }
}
